class DirhamSymbol extends StatelessWidget {
  const DirhamSymbol({
    super.key,
    this.color = const Color(0xFF1F1F1F),
    this.size = 20.0,
  });

  final Color color;
  final double size;

  @override
  Widget build(BuildContext context) {
    return CustomPaint(
      size: Size(size, size * (14 / 17)),
      painter: _DirhamPainter(color),
    );
  }
}

