  Path _parseSvgPath(String d) {
    final Path path = Path();
    final RegExp regex = RegExp(r'[A-Za-z]|[-0-9.]+');
    final matches = regex.allMatches(d).map((m) => m.group(0)!).toList();

    int i = 0;
    String cmd = '';
    double currentX = 0;
    double currentY = 0;

    double next() => double.parse(matches[i++]);

    while (i < matches.length) {
      String token = matches[i];
      if (RegExp(r'[A-Za-z]').hasMatch(token)) {
        cmd = token;
        i++;
      }
      
      switch (cmd) {
        case 'M':
          currentX = next(); currentY = next();
          path.moveTo(currentX, currentY);
          cmd = 'L'; // Subsequent pairs are treated as lineTo
          break;
        case 'L':
          currentX = next(); currentY = next();
          path.lineTo(currentX, currentY);
          break;
        case 'H':
          currentX = next();
          path.lineTo(currentX, currentY);
          break;
        case 'V':
          currentY = next();
          path.lineTo(currentX, currentY);
          break;
        case 'C':
          final x1 = next(); final y1 = next();
          final x2 = next(); final y2 = next();
          currentX = next(); currentY = next();
          path.cubicTo(x1, y1, x2, y2, currentX, currentY);
          break;
        case 'Z':
        case 'z':
          path.close();
          break;
      }
    }
    return path;
  }
